	/**
	 * Deterministic estimator: each predicate IRI names a "table" with a base row count; binding a listed variable
	 * multiplies the factor's rows by the configured selectivity. Honors the prefix-rows convention of the real
	 * estimators: output rows = prefix rows × factor rows under the bound variables.
	 */
	private static final class SyntheticCostModel implements JoinFactorCostModel {
		private final Map<String, Double> baseRows = new HashMap<>();
		private final Map<String, Double> baseWorkRows = new HashMap<>();
		private final Map<String, Map<String, Double>> boundVarSelectivity = new HashMap<>();

		SyntheticCostModel table(String predicateLocalName, double rows) {
			return table(predicateLocalName, rows, rows);
		}

		SyntheticCostModel table(String predicateLocalName, double rows, double workRows) {
			baseRows.put(predicateLocalName, rows);
			baseWorkRows.put(predicateLocalName, workRows);
			return this;
		}

		SyntheticCostModel boundSelectivity(String predicateLocalName, String varName, double selectivity) {
			boundVarSelectivity.computeIfAbsent(predicateLocalName, k -> new HashMap<>()).put(varName, selectivity);
			return this;
		}

		@Override
		public Optional<FactorCostEstimate> estimateFactorCost(TupleExpr factor, Set<String> currentlyBoundVars) {
			return estimate(factor, currentlyBoundVars, Double.NaN);
		}

		@Override
		public Optional<FactorCostEstimate> estimateFactorCost(TupleExpr factor, CostContext context) {
			return estimate(factor, context.getCurrentlyBoundVars(), context.getOuterPrefixRows());
		}

		private Optional<FactorCostEstimate> estimate(TupleExpr factor, Set<String> boundVars, double prefixRows) {
			TupleExpr estimateFactor = factor instanceof Extension extension ? extension.getArg() : factor;
			if (estimateFactor instanceof ArbitraryLengthPath path) {
				estimateFactor = path.getPathExpression();
			}
			if (!(estimateFactor instanceof StatementPattern pattern) || pattern.getPredicateVar().getValue() == null) {
				return Optional.empty();
			}
			String predicate = ((IRI) pattern.getPredicateVar().getValue()).getLocalName();
			Double base = baseRows.get(predicate);
			if (base == null) {
				return Optional.empty();
			}
			double rows = base;
			double workRows = baseWorkRows.getOrDefault(predicate, base);
			Map<String, Double> selectivities = boundVarSelectivity.getOrDefault(predicate, Map.of());
			List<Var> lookupVars = factor instanceof ArbitraryLengthPath path
					? List.of(path.getSubjectVar(), path.getObjectVar())
					: List.of(pattern.getSubjectVar(), pattern.getObjectVar());
			for (Var var : lookupVars) {
				if (!var.hasValue() && boundVars.contains(var.getName())) {
					double selectivity = selectivities.getOrDefault(var.getName(), 1.0d);
					rows *= selectivity;
					workRows *= selectivity;
				}
			}
			double output = Double.isFinite(prefixRows) && prefixRows > 0.0d ? prefixRows * rows : rows;
			double work = Double.isFinite(prefixRows) && prefixRows > 0.0d ? prefixRows * workRows : workRows;
			return Optional.of(new FactorCostEstimate(work, output));
		}
	}

	private static StatementPattern pattern(String subject, String predicateLocalName, String object) {
		return new StatementPattern(new Var(subject), new Var("p_" + predicateLocalName,
				VF.createIRI("urn:test:", predicateLocalName)), new Var(object));
	}

	private static TupleExpr joinIsland(TupleExpr... factors) {
		TupleExpr root = factors[0];
		for (int i = 1; i < factors.length; i++) {
			root = new Join(root, factors[i]);
		}
		return root;
	}

	private static Optional<LmdbCascadesConnectedJoinPlanner.Plan> plan(TupleExpr island,
			JoinFactorCostModel costModel) {
		return LmdbCascadesConnectedJoinPlanner.plan(island, Set.of(), costModel, new EvaluationStatistics());
	}

	private static List<StatementPattern> collectPatterns(TupleExpr tree) {
		List<StatementPattern> patterns = new ArrayList<>();
		tree.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(StatementPattern node) {
				patterns.add(node);
			}
		});
		return patterns;
	}

	private static boolean isLeftDeep(TupleExpr tree) {
		if (tree instanceof Join join) {
			return join.getRightArg() instanceof StatementPattern && isLeftDeep(join.getLeftArg());
		}
		return tree instanceof StatementPattern;
	}

	private static SyntheticCostModel starModel() {
		return new SyntheticCostModel()
				.table("a", 1000)
				.boundSelectivity("a", "s", 0.001d)
				.table("b", 100)
				.boundSelectivity("b", "s", 0.01d)
				.table("c", 10)
				.boundSelectivity("c", "s", 0.1d);
	}

	private static TupleExpr starIsland() {
		return joinIsland(pattern("s", "a", "o1"), pattern("s", "b", "o2"), pattern("s", "c", "o3"));
	}

