	@Test
	void bushyPlanWinsWhenStatisticsFavorIt() {
		System.setProperty(LmdbHypergraphJoinPlanner.DPHYP_PROPERTY, "true");
		// Chain a(?v1 ?v2) - b(?v2 ?v3) - c(?v3 ?v4) - d(?v4 ?v5): huge outer tables, selective outer joins, free
		// middle join. Left-deep must push a huge intermediate through the middle; bushy joins the two selective
		// pairs first. Bound selectivities are configured symmetrically so both probe directions agree on the
		// joined cardinality (|a⋈b| = |c⋈d| = 1000, |b⋈c| = 1e6).
		SyntheticCostModel model = new SyntheticCostModel()
				.table("a", 1_000_000)
				.boundSelectivity("a", "v2", 1e-6d)
				.table("b", 1000)
				.boundSelectivity("b", "v2", 1e-6d)
				.table("c", 1000)
				.boundSelectivity("c", "v4", 1e-6d)
				.table("d", 1_000_000)
				.boundSelectivity("d", "v4", 1e-6d);
		TupleExpr island = joinIsland(pattern("v1", "a", "v2"), pattern("v2", "b", "v3"),
				pattern("v3", "c", "v4"), pattern("v4", "d", "v5"));

		LmdbCascadesConnectedJoinPlanner.Plan result = plan(island, model).orElseThrow();
		assertEquals(LmdbHypergraphJoinPlanner.ALGORITHM, result.algorithm());
		assertFalse(isLeftDeep(result.tupleExpr()), "expected a bushy tree: " + result.tupleExpr());
		assertEquals(4, collectPatterns(result.tupleExpr()).size());
	}

