	@Test
	void declinesDisconnectedIslands() {
		SyntheticCostModel model = starModel().table("x", 50);
		// The third pattern shares no variable with the first two: a Cartesian product the dphyp core never builds.
		// The existing connected planner declines such islands too, so the flag must not change the outcome.
		TupleExpr island = joinIsland(pattern("s", "a", "o1"), pattern("s", "b", "o2"),
				pattern("t", "x", "u"));
		Optional<LmdbCascadesConnectedJoinPlanner.Plan> flagOff = plan(island, model);
		System.setProperty(LmdbHypergraphJoinPlanner.DPHYP_PROPERTY, "true");
		Optional<LmdbCascadesConnectedJoinPlanner.Plan> flagOn = plan(island, model);
		assertEquals(flagOff.isPresent(), flagOn.isPresent(),
				"enabling dphyp must not change whether a disconnected island gets a connected plan");
		flagOn.ifPresent(plan -> assertNotEquals(LmdbHypergraphJoinPlanner.ALGORITHM, plan.algorithm()));
	}

