	@Test
	void starRowEstimateSuppressesTransitiveSameVariableEdges() {
		System.setProperty(LmdbHypergraphJoinPlanner.DPHYP_PROPERTY, "true");
		LmdbCascadesConnectedJoinPlanner.Plan result = plan(starIsland(), starModel()).orElseThrow();
		// The three factors form a triangle of shared-?s edges. Only two same-variable equality predicates are
		// independent; the third is transitively implied. The canonical estimate keeps the least-reducing independent
		// spanning forest rather than multiplying the full clique.
		double expectedRows = 1000d * 100d * 10d
				* Math.sqrt(0.1d * 0.01d)
				* Math.sqrt(0.1d * 0.001d);
		assertEquals(expectedRows, result.cost().rows(), expectedRows * 0.01d);
	}

	@Test
	void subjectStarCardinalityUsesOnlyIndependentEqualityConstraints() {
		System.setProperty(LmdbHypergraphJoinPlanner.DPHYP_PROPERTY, "true");
		double rowsPerPattern = 1_000_000d;
		double distinctSubjects = 1_000d;
		double subjectSelectivity = 1.0d / distinctSubjects;
		SyntheticCostModel model = new SyntheticCostModel()
				.table("a", rowsPerPattern)
				.boundSelectivity("a", "s", subjectSelectivity)
				.table("b", rowsPerPattern)
				.boundSelectivity("b", "s", subjectSelectivity)
				.table("c", rowsPerPattern)
				.boundSelectivity("c", "s", subjectSelectivity);

		LmdbCascadesConnectedJoinPlanner.Plan result = plan(starIsland(), model).orElseThrow();

		double expectedRows = rowsPerPattern * rowsPerPattern * rowsPerPattern
				/ (distinctSubjects * distinctSubjects);
		assertEquals(expectedRows, result.cost().rows(), expectedRows * 0.01d,
				"three ?s star factors have only two independent equality constraints");
	}
